svg.script:
// Force XHTML namespace for dynamic elements
(function() {
  const ns = "http://www.w3.org/1999/xhtml";
  const b = document.getElementById("app-root");

  window.runTool = function() {
    const input = document.getElementById('tool-input').value;
    const out = document.getElementById('output');

    // Example logic: Base64 Encoder
    try {
        out.innerText = "Encoded: " + btoa(input);
        out.style.color = "#0f0";
    } catch(e) {
        out.innerText = "Error: Invalid Input";
        out.style.color = "#f00";
    }
  };
})();
